import{_ as b,o as e,c as a,j as p,a as t,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"魔法战队下属 锈色浩克","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 锈色浩克.md","filePath":"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 锈色浩克.md"}'),s={name:"4.资源分区/2.改造与功法/改造/4.综合类/魔法战队/魔法战队下属 锈色浩克.md"};function _(o,r,d,l,i,c){return e(),a("div",null,[...r[0]||(r[0]=[p("h1",{id:"魔法战队下属-锈色浩克",tabindex:"-1"},[t("魔法战队下属 锈色浩克 "),p("a",{class:"header-anchor",href:"#魔法战队下属-锈色浩克","aria-label":'Permalink to "魔法战队下属 锈色浩克"'},"​")],-1),p("table",{class:"bannerparthead"},[p("tbody",null,[p("tr",{id:"hdr"},[p("td",{class:"runninghead",nowrap:""},"TMD：新世短歌034")])])],-1),n('<h1 id="魔法战队下属-锈色浩克-1" tabindex="-1">魔法战队下属 锈色浩克 <a class="header-anchor" href="#魔法战队下属-锈色浩克-1" aria-label="Permalink to &quot;魔法战队下属 锈色浩克&quot;">​</a></h1><p>【魔法战队下属装备】<br> 魔法战队-锈色浩克<br> “在收集了前两次的数据后，我对旧时代的火炮进行了科技迭代。介于之前的护甲不得不降低防护性的经验，这次我结合了迷雾放射器装置，其中遍布的干扰粒子应该能起到良好的效果。”</p><p>【D级“锈色浩克”动力盔甲】<br> 代号：战机<br> 分类：轻甲<br> 基本属性：盔甲防御2/2<br> 特殊属性：无<br> 描述：战机是一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化护甲，是少有的可飞行装甲。<br> 外置装备：【外挂式机炮】【喷气式飞行器】</p><p>【外挂式机炮】：外挂式机炮视为一件机枪类武器，使用【敏捷属性+射击+专业：机枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>外挂式机炮的武器伤害为4L，武器体积4，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【贯穿】，【无限子弹】，速射等级【连射】，射程100米。</p><p>【喷气式飞行器】：启动喷气式飞行器是一个移动动作，随后在该场景内你获得等同基础移动速度的飞行能力，机动性普通；在这一等级下，飞行器的防护较为脆弱，因此你获得【物理易伤1】。</p><p>代号：重炮<br> 分类：重甲<br> 基本属性：遮蔽防御4/4，盔甲减值3<br> 特殊属性：无<br> 描述：重炮一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置护甲与迷雾装置。重炮的武装毫无新意，但实践证明它永远足够“实用”。<br> 外置装备：【穿甲火炮】【迷雾放射器】</p><p>【穿甲火炮】：穿甲火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。<br> 穿甲火炮的武器伤害为8L，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲3】【无限子弹】【双手】，速射等级【无】，射程200米。</p><p>【迷雾放射器】：重炮提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于重甲并带来盔甲防御提升的效果，对于重炮而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>代号：蜘蛛<br> 分类：轻甲<br> 基本属性：遮蔽防御2/2<br> 特殊属性：无<br> 描述：蜘蛛一件中型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化的护甲与迷雾装置。蜘蛛武装的特色在于它能抛射多个自走型炸弹，并在爆炸后形成大片迷雾。<br> 外置装备：【子母弹】【迷雾放射器】</p><p>【子母弹】：子母弹视为一件冲锋枪类武器，使用【敏捷属性+射击+专业：冲锋枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>子母弹的武器伤害为3L，武器体积3，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【连射】，射程20米。</p><p>在这一等级下，子母弹攻击后会额外分裂出一个小型自走炸弹，对于你攻击范围内的一个敌对目标进行一次相同的攻击（等于多目标攻击能力，无法选择同一目标），若不存在额外敌对目标则无法分裂；当你使用子母弹进行攻击后，你获得1点掩蔽防御，持续一轮。</p><p>【迷雾放射器】：蜘蛛提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于蜘蛛并带来盔甲防御提升的效果，对于蜘蛛而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>【C级“锈色浩克”动力盔甲】<br> 代号：战机<br> 分类：轻甲<br> 基本属性：盔甲防御10/10<br> 特殊属性：无<br> 描述：战机是一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化护甲，是少有的可飞行装甲。<br> 外置装备：【外挂式机炮】【喷气式飞行器】</p><p>【外挂式机炮】：外挂式机炮视为一件机枪类武器，使用【敏捷属性+射击+专业：机枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>外挂式机炮的武器伤害为12L，武器体积4，伤害类型：物理-穿刺，具有【高速10】（已计入远程武器自带的高速），【贯穿】，【无限子弹】，速射等级【连射】，射程100米。</p><p>【喷气式飞行器】：你获得等同基础移动速度的飞行速度，机动性普通（这是因为技术迭代导致的结果，不再需要如同D级一样消费移动动作，也没有持续时间限制）。</p><p>代号：重炮<br> 分类：重甲<br> 基本属性：遮蔽防御12/12，盔甲减值3<br> 特殊属性：无<br> 描述：重炮一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置护甲与迷雾装置。重炮的武装毫无新意，但实践证明它永远足够“实用”。<br> 外置装备：【穿甲火炮】【迷雾放射器】</p><p>【穿甲火炮】：穿甲火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。<br> 穿甲火炮的武器伤害为13L，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲3】【无限子弹】【双手】，速射等级【无】，射程200米。</p><p>【迷雾放射器】：重炮提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于重甲并带来盔甲防御提升的效果，对于重炮而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>你可以消费一个移动动作提升迷雾放射器的功率，随后在该场景内以你为中心触及范围内的所有友方单位（包括自身）额外获得5点遮蔽防御。</p><p>代号：蜘蛛<br> 分类：轻甲<br> 基本属性：遮蔽防御10/10<br> 特殊属性：无<br> 描述：蜘蛛一件中型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化的护甲与迷雾装置。蜘蛛武装的特色在于它能抛射多个自走型炸弹，并在爆炸后形成大片迷雾。<br> 外置装备：【子母弹】【迷雾放射器】</p><p>【子母弹】：子母弹视为一件冲锋枪类武器，使用【敏捷属性+射击+专业：冲锋枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>子母弹的武器伤害为11L，武器体积3，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【无限子弹】，速射等级【连射】，射程20米。</p><p>子母弹攻击后会额外分裂出小型自走炸弹，这意味着子母弹会对你前方射程范围内的所有敌对目标进行攻击，目标正常进行防御流程对抗攻击。</p><p>【迷雾放射器】：蜘蛛提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于蜘蛛并带来盔甲防御提升的效果，对于蜘蛛而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>【B级“锈色浩克”动力盔甲】<br> 代号：战机<br> 分类：轻甲<br> 基本属性：盔甲防御17/17<br> 特殊属性：无<br> 描述：战机是一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化护甲，是少有的可飞行装甲。<br> 外置装备：【外挂式机炮】【喷气式飞行器】</p><p>【外挂式机炮】：外挂式机炮视为一件机枪类武器，使用【敏捷属性+射击+专业：机枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>外挂式机炮的武器伤害为19L，武器体积4，伤害类型：物理-穿刺，具有【高速10】（已计入远程武器自带的高速），【贯穿】，【8加骰】，【无限子弹】，速射等级【连射】，射程100米。</p><p>【喷气式飞行器】：你获得等同基础移动速度的飞行速度，机动性良好（这是因为技术迭代导致的结果，不再需要如同D级一样消费移动动作，也没有持续时间限制）。</p><p>代号：重炮<br> 分类：重甲<br> 基本属性：遮蔽防御19/19，盔甲减值3<br> 特殊属性：无<br> 描述：重炮一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置护甲与迷雾装置。重炮的武装毫无新意，但实践证明它永远足够“实用”。<br> 外置装备：【穿甲火炮】【迷雾放射器】</p><p>【穿甲火炮】：穿甲火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。<br> 穿甲火炮的武器伤害为20L，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲4】【无限子弹】【双手】，速射等级【无】，射程200米。</p><p>【迷雾放射器】：重炮提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于重甲并带来盔甲防御提升的效果，对于重炮而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>你可以消费一个自由动作提升迷雾放射器的功率，随后在该场景内以你为中心触及范围内的所有友方单位（包括自身）额外获得8点遮蔽防御，并在反射豁免上获得【8加骰】。</p><p>代号：蜘蛛<br> 分类：轻甲<br> 基本属性：遮蔽防御17/17<br> 特殊属性：无<br> 描述：蜘蛛一件中型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化的护甲与迷雾装置。蜘蛛武装的特色在于它能抛射多个自走型炸弹，并在爆炸后形成大片迷雾。<br> 外置装备：【子母弹】【迷雾放射器】</p><p>【子母弹】：子母弹视为一件冲锋枪类武器，使用【敏捷属性+射击+专业：冲锋枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>子母弹的武器伤害为18L，武器体积3，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【幻灭】，【无限子弹】，速射等级【连射】，射程20米。</p><p>子母弹攻击后会额外分裂出小型自走炸弹，这意味着子母弹会对以你自身为中心，半径等同射程范围内的所有敌对目标进行攻击，目标正常进行防御流程对抗攻击。</p><p>【迷雾放射器】：蜘蛛提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于蜘蛛并带来盔甲防御提升的效果，对于蜘蛛而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>【A级“锈色浩克”动力盔甲】<br> 代号：战机<br> 分类：轻甲<br> 基本属性：盔甲防御26/26，基于盔甲2个防御附加<br> 特殊属性：无<br> 描述：战机是一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化护甲，是少有的可飞行装甲。<br> 外置装备：【外挂式机炮】【喷气式飞行器】</p><p>【外挂式机炮】：外挂式机炮视为一件机枪类武器，使用【敏捷属性+射击+专业：机枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>外挂式机炮的武器伤害为28L，额外获得2个攻击附加成功数，武器体积4，伤害类型：物理-穿刺，具有【高速12】（已计入远程武器自带的高速），【贯穿】，【8加骰】，【无限子弹】，速射等级【连射】，射程100米。</p><p>外挂式机炮进行的攻击忽略闪避防御，这是一个A级创伤来源的效果。</p><p>【喷气式飞行器】：你获得等同基础移动速度的飞行速度，机动性良好（这是因为技术迭代导致的结果，不再需要如同D级一样消费移动动作，也没有持续时间限制）。</p><p>代号：重炮<br> 分类：重甲<br> 基本属性：遮蔽防御28/28，基于遮蔽2个防御附加，盔甲减值3<br> 特殊属性：无<br> 描述：重炮一件大型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置护甲与迷雾装置。重炮的武装毫无新意，但实践证明它永远足够“实用”。<br> 外置装备：【穿甲火炮】【迷雾放射器】</p><p>【穿甲火炮】：穿甲火炮视为一件炮专业武器，使用【敏捷属性+射击+专业：炮+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。<br> 穿甲火炮的武器伤害为30L，额外获得2个攻击附加成功数，武器体积5，伤害类型：物理-穿刺，具有【高速5】（已计入远程武器自带的高速），【破甲4】【无限子弹】【双手】，速射等级【无】，射程200米。</p><p>【迷雾放射器】：重炮提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于重甲并带来盔甲防御提升的效果，对于重炮而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御；此外，重炮具有基于掩蔽防御的【折射】特性。</p><p>你可以消费一个自由动作提升迷雾放射器的功率，随后在该场景内以你为中心触及范围内的所有友方单位（包括自身）额外获得8点遮蔽防御，并在反射豁免上获得【8加骰】。</p><p>代号：蜘蛛<br> 分类：轻甲<br> 基本属性：遮蔽防御26/26，基于遮蔽2个防御附加<br> 特殊属性：无<br> 描述：蜘蛛一件中型外骨骼动力装甲，其外观主要以橙色为主，在外表各处存在外置轻量化的护甲与迷雾装置。蜘蛛武装的特色在于它能抛射多个自走型炸弹，并在爆炸后形成大片迷雾。<br> 外置装备：【子母弹】【迷雾放射器】</p><p>【子母弹】：子母弹视为一件冲锋枪类武器，使用【敏捷属性+射击+专业：冲锋枪+辅助专业：弹道学+武器伤害+其他加值（若有）】进行攻击，在着装盔甲时会同步被你持有。</p><p>子母弹的武器伤害为36L，额外获得2个攻击附加成功数，武器体积3，伤害类型：物理-穿刺，具有【高速10】（已计入远程武器自带的高速），【幻灭】，【无限子弹】，速射等级【连射】，射程等同持有者的敏感范围。</p><p>子母弹攻击后会额外分裂出小型自走炸弹，这意味着子母弹会对以你自身为中心，半径等同射程范围内的所有敌对目标进行攻击，可以选择令目标使用反射豁免而非正常防御。</p><p>【迷雾放射器】：蜘蛛提供的防御并非是盔甲防御，而是永久性改为遮蔽防御；任何应用于蜘蛛并带来盔甲防御提升的效果，对于蜘蛛而言皆改为提升遮蔽防御，但无法使其他效果中基于盔甲防御的特性改为基于遮蔽防御。</p><p>【S级“锈色浩克”动力盔甲】<br> 待补充。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',57)])])}const L=b(s,[["render",_]]);export{f as __pageData,L as default};
